package genxsolution.vms.vmsbackend.employee_hr_management.payroll_deduction.controller;
import genxsolution.vms.vmsbackend.common.query.ListQueryEngine; import genxsolution.vms.vmsbackend.employee_hr_management.payroll_deduction.dto.*; import genxsolution.vms.vmsbackend.employee_hr_management.payroll_deduction.service.PayrollDeductionService; import org.springframework.http.HttpStatus; import org.springframework.web.bind.annotation.*; import java.util.*;
@RestController @RequestMapping("/api/v1/hr/payroll-deductions") public class PayrollDeductionController { private final PayrollDeductionService service; public PayrollDeductionController(PayrollDeductionService service){this.service=service;} @GetMapping public List<PayrollDeductionResponse> list(@RequestParam(required=false) UUID companyId,@RequestParam Map<String,String> filters){ return ListQueryEngine.apply(service.list(companyId), filters, Set.of("companyId")); } @GetMapping("/{id}") public PayrollDeductionResponse getById(@PathVariable UUID id){ return service.getById(id);} @PostMapping @ResponseStatus(HttpStatus.CREATED) public PayrollDeductionResponse create(@RequestBody PayrollDeductionUpsertRequest r){ return service.create(r);} @PutMapping("/{id}") public PayrollDeductionResponse update(@PathVariable UUID id,@RequestBody PayrollDeductionUpsertRequest r){ return service.update(id,r);} @DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable UUID id){ service.delete(id);} }
